		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "url is required"})
	}

	fetchCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(fetchCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "invalid url"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "received non-success status code from url"})
	}

	doc, err := html.Parse(resp.Body)
	if err != nil {
