func extractPreview(n *html.Node) (string, string) {
	var title string
	var description string

	var walk func(*html.Node)
	walk = func(node *html.Node) {
		if node == nil || (title != "" && description != "") {
			return
		}

		if node.Type == html.ElementNode {
			if node.Data == "title" && title == "" {
