)

const (
	maxRequestBodyBytes  = 4096
	maxResponseBodyBytes = 1024 * 1024 // 1 MiB
	requestTimeout       = 5 * time.Second
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)

	ctx.Request().Body = http.MaxBytesReader(ctx.Response(), ctx.Request().Body, maxRequestBodyBytes)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON"})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || !parsedURL.IsAbs() || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}

	if parsedURL.User != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "user info in URL is not allowed"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "only HTTP/HTTPS URLs are allowed"})
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid host"})
	}

	if err := validateResolvedHost(hostname); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "target host is not allowed"})
	}

	client := &http.Client{
		Timeout: requestTimeout,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}
			if req.URL == nil {
				return errors.New("invalid redirect URL")
			}
			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return errors.New("redirected to unsupported scheme")
			}
			if req.URL.User != nil {
				return errors.New("redirected URL contains user info")
			}
			host := req.URL.Hostname()
			if host == "" {
				return errors.New("redirected URL missing host")
			}
			if err := validateResolvedHost(host); err != nil {
				return err
			}
			return nil
		},
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "upstream returned non-200 status"})
	}

	contentType := strings.ToLower(resp.Header.Get("Content-Type"))
	if contentType != "" && !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
