	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func validateResolvedHost(host string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupNetIP(ctx, "ip", host)
	if err != nil {
		return err
	}

	if len(ips) == 0 {
		return errors.New("no IPs resolved")
	}

	for _, ip := range ips {
		if !ip.IsValid() {
			return errors.New("invalid resolved IP")
		}
		if isPrivateOrRestrictedIP(ip) {
			return errors.New("resolved to private or restricted IP")
		}
	}

	return nil
}

func isPrivateOrRestrictedIP(ip netip.Addr) bool {
	ip = ip.Unmap()

	if !ip.IsValid() {
		return true
	}

	if ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsMulticast() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsUnspecified() {
		return true
	}

	if ip.Is4() {
		v4 := ip.As4()
		// 100.64.0.0/10 shared address space
		if v4[0] == 100 && v4[1] >= 64 && v4[1] <= 127 {
			return true
		}
		// 169.254.0.0/16 link-local (already covered, kept explicit)
		if v4[0] == 169 && v4[1] == 254 {
			return true
		}
		// 198.18.0.0/15 benchmarking
		if v4[0] == 198 && (v4[1] == 18 || v4[1] == 19) {
			return true
		}
		// 0.0.0.0/8
		if v4[0] == 0 {
			return true
		}
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var walk func(*html.Node)

	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					if key == "name" || key == "property" {
						name = strings.ToLower(val)
					}
					if key == "content" {
						content = val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description
}

