	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "failed to parse html"})
	}

	title, description := extractPreview(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractPreview(n *html.Node) (string, string) {
	var title string
	var description string

	var walk func(*html.Node)
	walk = func(node *html.Node) {
		if node == nil || (title != "" && description != "") {
			return
		}

		if node.Type == html.ElementNode {
			if node.Data == "title" && title == "" {
