package main

import (
	"context"
	"net/http"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "invalid request body"})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "url is required"})
	}

	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "url must start with http:// or https://"})
	}

	requestCtx, cancel := context.WithTimeout(ctx.Request().Context(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(requestCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "invalid url"})
	}

	httpReq.Header.Set("User-Agent", "url-preview-bot/1.0")

	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "received non-success status from target url"})
	}

	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "failed to parse html"})
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	description, exists := doc.Find(`meta[name="description"]`).Attr("content")
	if !exists || strings.TrimSpace(description) == "" {
		description, _ = doc.Find(`meta[property="og:description"]`).Attr("content")
	}
	description = strings.TrimSpace(description)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

