	}

	ips, err := net.DefaultResolver.LookupNetIP(context.Background(), "ip", host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("host did not resolve")
	}

	for _, ip := range ips {
		if isPrivateOrUnsafeIP(ip) {
			return errors.New("disallowed host")
		}
	}
	return nil
