package main

import (
	"net/http"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid request body",
		})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "url is required",
		})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	httpReq, err := http.NewRequest(http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid url",
		})
	}

	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{
			Error: "failed to fetch url",
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{
			Error: "received non-success status from target url",
		})
	}

	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to parse html",
		})
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())

	description := ""
	if metaDescription, exists := doc.Find(`meta[name="description"]`).Attr("content"); exists {
		description = strings.TrimSpace(metaDescription)
	} else if ogDescription, exists := doc.Find(`meta[property="og:description"]`).Attr("content"); exists {
		description = strings.TrimSpace(ogDescription)
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	if err := e.Start(":8080"); err != nil && err != http.ErrServerClosed {
		e.Logger.Fatal(err)
	}
}

